export type CampusZone = 'Academic' | 'Hostels' | 'Admin' | 'Gate' | 'Mess' | 'Unknown';

export interface Errand {
  id: string;
  studentName: string;
  requestText: string;
  item: string;
  source: string;
  location: string;
  zone: CampusZone;
  price: number;
  status: 'Pending' | 'Active' | 'Completed';
  timestamp: number;
  isInternal: boolean;
  notes?: string;
}

export interface AIResponse {
  item: string;
  source: string;
  location: string;
  zone: CampusZone;
  isInternal: boolean;
  isCrossCampus: boolean;
  notes?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are the logistics coordinator for 'Embu CampusRunner.' You know the University of Embu layout perfectly.
Main Landmarks: The Gate, New Library, Graduation Square, School of Agriculture, Hostel blocks (Ngiri, Simba, Chui, etc.), the Mess, Science Labs, School of Nursing, Old Admin Block.

Your Task: When a student sends a request, identify the item they want, where it's coming from, and where it needs to go.

Mapping Rules:
1. If they are in the New Library, remind them that deliveries must be met at the entrance.
2. If they are in Hostels (Ngiri, Simba, etc.), ask for the room number if not provided.
3. Determine if the trip is "Internal" (source and destination are within the university).
4. Determine if it is "Cross-Campus" (e.g., Main Gate to far Hostels, or Admin to Nursing).

Output MUST be a structured JSON response.`;

export const parseErrandRequest = async (userInput: string): Promise<AIResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: userInput,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING, description: "The specific item being requested." },
          source: { type: Type.STRING, description: "Where the item should be picked up (e.g., The Mess)." },
          location: { type: Type.STRING, description: "The destination building or landmark." },
          zone: { 
            type: Type.STRING, 
            enum: ['Academic', 'Hostels', 'Admin', 'Gate', 'Mess', 'Unknown'],
            description: "The specific zone of the destination." 
          },
          isInternal: { type: Type.BOOLEAN, description: "True if both source and location are on campus." },
          isCrossCampus: { type: Type.BOOLEAN, description: "True if the distance is significant (e.g., Gate to Hostels)." },
          notes: { type: Type.STRING, description: "Any specific instructions based on the location (e.g., 'Meet at library entrance')." }
        },
        required: ["item", "source", "location", "zone", "isInternal", "isCrossCampus"]
      }
    }
  });

  try {
    const text = response.text;
    return JSON.parse(text) as AIResponse;
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    throw new Error("Could not understand the errand request. Please be more specific.");
  }
};

