import React, { useState } from 'react';
import { parseErrandRequest } from '../services/geminiService';
import { Errand } from '../types';

interface OrderFormProps {
  onOrderPlaced: (errand: Errand) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ onOrderPlaced }) => {
  const [request, setRequest] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!request.trim()) return;

    setIsLoading(true);
    setError('');

    try {
      const result = await parseErrandRequest(request);

      const baseFee = 30;
      const distanceFee = result.isCrossCampus ? 10 : 0;

      const newErrand: Errand = {
        id: Math.random().toString(36).substr(2, 9),
        studentName: "Student User", // Mock name
        requestText: request,
        item: result.item,
        source: result.source,
        location: result.location,
        zone: result.zone,
        price: baseFee + distanceFee,
        status: 'Pending',
        timestamp: Date.now(),
        isInternal: result.isInternal,
        notes: result.notes
      };

      onOrderPlaced(newErrand);
      setRequest('');
      alert(`Order placed! Total: KES ${newErrand.price}. Location: ${newErrand.location}. ${newErrand.notes || ''}`);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section className="p-4 bg-white rounded-xl shadow-md border border-gray-100 max-w-2xl mx-auto mt-6">
      <h2 className="text-xl font-bold text-embu-green mb-4">New Errand</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            What do you need?
          </label>
          <textarea
            value={request}
            onChange={(e) => setRequest(e.target.value)}
            placeholder="e.g., I'm at the Science Labs, bring me a snack from the Mess"
            className="w-full p-4 border rounded-lg focus:ring-2 focus:ring-embu-green focus:border-embu-green h-32 text-gray-800 transition-all"
            required
          />
        </div>

        {error && <p className="text-red-500 text-sm font-medium bg-red-50 p-2 rounded">{error}</p>}

        <button
          type="submit"
          disabled={isLoading}
          className={`w-full py-4 rounded-lg font-bold text-lg shadow-lg transition-all ${
            isLoading 
            ? 'bg-gray-300 cursor-not-allowed text-gray-500' 
            : 'bg-embu-green hover:bg-embu-darkGreen text-white active:scale-[0.98]'
          }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center gap-2">
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Optimizing Route...
            </span>
          ) : 'Request Errand'}
        </button>
      </form>
      <div className="mt-4 flex gap-4 text-xs font-semibold text-gray-500">
        <span className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-embu-gold" /> Base 30 KES
        </span>
        <span className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-embu-green" /> +10 KES Long Distance
        </span>
      </div>
    </section>
  );
};

export default OrderForm;

import React, { useMemo } from 'react';
import { Errand } from '../types';

interface RunnerDashboardProps {
  errands: Errand[];
  onComplete: (id: string) => void;
}

const RunnerDashboard: React.FC<RunnerDashboardProps> = ({ errands, onComplete }) => {
  const pendingErrands = useMemo(() => 
    errands.filter(e => e.status !== 'Completed'), 
    [errands]
  );

  // Group errands by location
  const groupedErrands = useMemo(() => {
    const groups: Record<string, Errand[]> = {};
    pendingErrands.forEach(errand => {
      if (!groups[errand.location]) {
        groups[errand.location] = [];
      }
      groups[errand.location].push(errand);
    });
    return groups;
  }, [pendingErrands]);

  const totalPossibleEarnings = useMemo(() => 
    pendingErrands.reduce((sum, e) => sum + e.price, 0),
    [pendingErrands]
  );

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-embu-green p-6 rounded-2xl text-white shadow-xl flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Runner Dashboard</h2>
          <p className="text-embu-gold font-medium">University of Embu Logistics</p>
        </div>
        <div className="text-right">
          <div className="text-sm opacity-80">Pending Earnings</div>
          <div className="text-3xl font-bold">KES {totalPossibleEarnings}</div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {Object.entries(groupedErrands).length === 0 ? (
          <div className="col-span-full py-20 text-center bg-white rounded-xl border-2 border-dashed border-gray-200">
            <p className="text-gray-400 font-medium">No active errands right now.</p>
          </div>
        ) : (
          Object.entries(groupedErrands).map(([location, group]) => (
            <div key={location} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-4 py-3 border-b flex justify-between items-center">
                <h3 className="font-bold text-embu-green flex items-center gap-2">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                  {location}
                </h3>
                <span className="bg-embu-gold text-embu-green px-2 py-0.5 rounded text-xs font-bold">
                  {group.length} {group.length === 1 ? 'Task' : 'Tasks'}
                </span>
              </div>
              <ul className="divide-y">
                {group.map(errand => (
                  <li key={errand.id} className="p-4 hover:bg-gray-50 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <div className="font-bold text-gray-800">{errand.item}</div>
                      <div className="text-embu-green font-bold text-sm">KES {errand.price}</div>
                    </div>
                    <div className="text-sm text-gray-600 mb-3 flex items-center gap-1">
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                      </svg>
                      From: {errand.source}
                    </div>
                    {errand.notes && (
                      <div className="text-xs italic text-orange-600 bg-orange-50 p-2 rounded mb-3">
                        Note: {errand.notes}
                      </div>
                    )}
                    <button
                      onClick={() => onComplete(errand.id)}
                      className="w-full py-2 bg-gray-100 hover:bg-embu-green hover:text-white text-gray-700 rounded-lg text-sm font-bold transition-all border border-gray-200"
                    >
                      Mark Delivered
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default RunnerDashboard;

import React, { useState, useEffect } from 'react';
import { Errand } from './types';
import Header from './components/Header';
import OrderForm from './components/OrderForm';
import RunnerDashboard from './components/RunnerDashboard';

const App: React.FC = () => {
  const [view, setView] = useState<'student' | 'runner'>('student');
  const [errands, setErrands] = useState<Errand[]>([]);

  // Load initial data from local storage if needed
  useEffect(() => {
    const saved = localStorage.getItem('embu-errands');
    if (saved) {
      setErrands(JSON.parse(saved));
    }
  }, []);

  // Save data to local storage
  useEffect(() => {
    localStorage.setItem('embu-errands', JSON.stringify(errands));
  }, [errands]);

  const handleOrderPlaced = (newErrand: Errand) => {
    setErrands(prev => [newErrand, ...prev]);
  };

  const handleCompleteErrand = (id: string) => {
    setErrands(prev => prev.map(e => 
      e.id === id ? { ...e, status: 'Completed' } : e
    ));
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <Header view={view} setView={setView} />

      <main className="container mx-auto max-w-4xl pt-4">
        {view === 'student' ? (
          <div className="space-y-8">
            <div className="text-center px-4 mt-6">
              <h2 className="text-3xl font-black text-embu-green leading-tight">
                Embu <span className="text-embu-gold">CampusRunner</span>
              </h2>
              <p className="text-gray-600 mt-2 max-w-md mx-auto">
                The fastest way to move items across University of Embu. No trekking needed.
              </p>
            </div>

            <OrderForm onOrderPlaced={handleOrderPlaced} />

            <section className="px-4">
              <h3 className="text-lg font-bold text-gray-800 mb-4">Your Recent Orders</h3>
              {errands.length === 0 ? (
                <p className="text-gray-400 text-sm italic">You haven't placed any orders yet.</p>
              ) : (
                <div className="space-y-3">
                  {errands.slice(0, 5).map(order => (
                    <div key={order.id} className="bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center">
                      <div>
                        <div className="font-bold text-embu-green">{order.item}</div>
                        <div className="text-xs text-gray-500">To: {order.location}</div>
                      </div>
                      <div className="text-right">
                        <div className={`text-xs font-bold px-2 py-1 rounded ${
                          order.status === 'Completed' ? 'bg-green-100 text-green-700' : 'bg-embu-gold text-embu-green'
                        }`}>
                          {order.status}
                        </div>
                        <div className="text-sm font-bold mt-1">KES {order.price}</div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        ) : (
          <RunnerDashboard 
            errands={errands} 
            onComplete={handleCompleteErrand} 
          />
        )}
      </main>

      {/* Persistent Call to Action for Student View */}
      {view === 'student' && (
        <div className="fixed bottom-6 right-6 lg:hidden">
          <button 
             onClick={() => {
                const form = document.querySelector('form');
                form?.scrollIntoView({ behavior: 'smooth' });
             }}
             className="bg-embu-green text-white p-4 rounded-full shadow-2xl border-4 border-embu-gold flex items-center justify-center animate-bounce"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
            </svg>
          </button>
        </div>
      )}

      {/* Mobile Footer Branding */}
      <footer className="fixed bottom-0 w-full bg-white border-t border-gray-200 py-3 text-center text-[10px] text-gray-400 font-bold uppercase tracking-widest">
        Powered by Google Gemini 3.0 Pro &bull; University of Embu Logistics
      </footer>
    </div>
  );
};

export default App;

export type CampusZone = 'Academic' | 'Hostels' | 'Admin' | 'Gate' | 'Mess' | 'Unknown';

