import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are the logistics coordinator for 'Embu CampusRunner.' You know the University of Embu layout perfectly.
Main Landmarks: 
- The Gate (-0.5050, 37.4580)
- New Library (-0.5065, 37.4595)
- Graduation Square (-0.5070, 37.4590)
- School of Agriculture (-0.5080, 37.4610)
- Hostel Ngiri (-0.5100, 37.4620)
- Hostel Simba (-0.5110, 37.4625)
- The Mess (-0.5075, 37.4600)
- Science Labs (-0.5060, 37.4590)
- School of Nursing (-0.5085, 37.4615)
- Old Admin Block (-0.5055, 37.4585)

Your Task: When a student sends a request, identify the item, source, location, and approximate coordinates for that location.

Mapping Rules:
1. If they are in the New Library, remind them that deliveries must be met at the entrance.
2. If they are in Hostels, ask for the room number if not provided.
3. Determine if the trip is "Internal" and "Cross-Campus".
4. Provide approximate lat/lng coordinates based on the landmarks above.

Output MUST be a structured JSON response.`;

export const parseErrandRequest = async (userInput: string): Promise<AIResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: userInput,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          source: { type: Type.STRING },
          location: { type: Type.STRING },
          zone: { 
            type: Type.STRING, 
            enum: ['Academic', 'Hostels', 'Admin', 'Gate', 'Mess', 'Unknown']
          },
          isInternal: { type: Type.BOOLEAN },
          isCrossCampus: { type: Type.BOOLEAN },
          notes: { type: Type.STRING },
          approxDestinationCoords: {
            type: Type.OBJECT,
            properties: {
              lat: { type: Type.NUMBER },
              lng: { type: Type.NUMBER }
            },
            required: ["lat", "lng"]
          }
        },
        required: ["item", "source", "location", "zone", "isInternal", "isCrossCampus", "approxDestinationCoords"]
      }
    }
  });

  try {
    const text = response.text;
    return JSON.parse(text) as AIResponse;
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    throw new Error("Could not understand the errand request. Please be more specific about the Embu Uni location.");
  }
};

import React from 'react';
import { Coords } from '../types';

interface TrackingMapProps {
  runnerCoords: Coords;
  destCoords?: Coords;
  zoom?: number;
}

const TrackingMap: React.FC<TrackingMapProps> = ({ runnerCoords, destCoords, zoom = 16 }) => {
  // We use OpenStreetMap via an iframe for a simple, zero-key mapping solution.
  // In a production app, we would use a library like Leaflet or React Google Maps.
  const mapUrl = `https://www.openstreetmap.org/export/embed.html?bbox=${runnerCoords.lng - 0.005}%2C${runnerCoords.lat - 0.005}%2C${runnerCoords.lng + 0.005}%2C${runnerCoords.lat + 0.005}&layer=mapnik&marker=${runnerCoords.lat}%2C${runnerCoords.lng}`;

  return (
    <div className="relative w-full h-48 bg-gray-200 rounded-lg overflow-hidden border border-gray-300">
      <iframe
        width="100%"
        height="100%"
        frameBorder="0"
        scrolling="no"
        marginHeight={0}
        marginWidth={0}
        src={mapUrl}
        title="Runner Location Map"
      ></iframe>
      <div className="absolute top-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded shadow text-[10px] font-bold text-embu-green">
        LIVE TRACKING
      </div>
    </div>
  );
};

export default TrackingMap;

import React, { useMemo, useEffect, useState } from 'react';
import { Errand, Coords } from '../types';

interface RunnerDashboardProps {
  errands: Errand[];
  onComplete: (id: string) => void;
  onUpdateLocation: (id: string, coords: Coords, eta: string) => void;
  onStartErrand: (id: string) => void;
}

const RunnerDashboard: React.FC<RunnerDashboardProps> = ({ errands, onComplete, onUpdateLocation, onStartErrand }) => {
  const [activeTrackingId, setActiveTrackingId] = useState<string | null>(null);

  const pendingErrands = useMemo(() => 
    errands.filter(e => e.status !== 'Completed'), 
    [errands]
  );

  useEffect(() => {
    let watchId: number;

    if (activeTrackingId) {
      if ('geolocation' in navigator) {
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            const coords = {
              lat: position.coords.latitude,
              lng: position.coords.longitude
            };

            // Simple ETA Calculation: Assume walking speed of 5km/h (1.4m/s)
            // University scale is small, so we mock a realistic-looking time
            const mockEta = Math.floor(Math.random() * 5) + 2; // 2-7 mins
            onUpdateLocation(activeTrackingId, coords, `${mockEta} mins`);
          },
          (error) => console.error("GPS Error:", error),
          { enableHighAccuracy: true }
        );
      }
    }

    return () => {
      if (watchId) navigator.geolocation.clearWatch(watchId);
    };
  }, [activeTrackingId, onUpdateLocation]);

  const groupedErrands = useMemo(() => {
    const groups: Record<string, Errand[]> = {};
    pendingErrands.forEach(errand => {
      if (!groups[errand.location]) {
        groups[errand.location] = [];
      }
      groups[errand.location].push(errand);
    });
    return groups;
  }, [pendingErrands]);

  const handleStart = (id: string) => {
    setActiveTrackingId(id);
    onStartErrand(id);
  };

  const handleFinish = (id: string) => {
    if (activeTrackingId === id) setActiveTrackingId(null);
    onComplete(id);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-embu-green p-6 rounded-2xl text-white shadow-xl flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Runner Dashboard</h2>
          <p className="text-embu-gold font-medium">Campus Logistics Console</p>
        </div>
        <div className="bg-white/10 p-3 rounded-lg border border-white/20">
          <div className="text-[10px] uppercase opacity-70 tracking-widest font-bold">Runner Status</div>
          <div className="flex items-center gap-2 text-sm font-bold">
            <div className={`w-2 h-2 rounded-full animate-pulse ${activeTrackingId ? 'bg-green-400' : 'bg-embu-gold'}`} />
            {activeTrackingId ? 'Tracking Active' : 'Waiting for Tasks'}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {Object.entries(groupedErrands).length === 0 ? (
          <div className="col-span-full py-20 text-center bg-white rounded-xl border-2 border-dashed border-gray-200">
            <p className="text-gray-400 font-medium">No active errands. Enjoy the break!</p>
          </div>
        ) : (
          Object.entries(groupedErrands).map(([location, group]) => (
            <div key={location} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-4 py-3 border-b flex justify-between items-center">
                <h3 className="font-bold text-embu-green truncate">{location}</h3>
                <span className="bg-embu-gold text-embu-green px-2 py-0.5 rounded text-[10px] font-black">
                  {group.length} TASK{group.length > 1 ? 'S' : ''}
                </span>
              </div>
              <ul className="divide-y">
                {group.map(errand => (
                  <li key={errand.id} className={`p-4 transition-all ${activeTrackingId === errand.id ? 'bg-embu-green/5 ring-2 ring-embu-green ring-inset' : ''}`}>
                    <div className="flex justify-between items-start mb-2">
                      <div className="font-bold text-gray-800">{errand.item}</div>
                      <div className="text-embu-green font-bold text-sm">KES {errand.price}</div>
                    </div>
                    <div className="text-xs text-gray-500 mb-4">Pick-up: {errand.source}</div>

                    {errand.status === 'Active' ? (
                      <div className="space-y-3">
                        <div className="bg-white border rounded p-2 text-[10px] flex items-center justify-between">
                          <span className="text-gray-400">GPS Signal:</span>
                          <span className="font-bold text-green-600">Stable</span>
                        </div>
                        <button
                          onClick={() => handleFinish(errand.id)}
                          className="w-full py-2.5 bg-embu-green text-white rounded-lg text-sm font-bold shadow-md hover:bg-embu-darkGreen"
                        >
                          Complete Delivery
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => handleStart(errand.id)}
                        disabled={!!activeTrackingId}
                        className={`w-full py-2.5 rounded-lg text-sm font-bold border-2 transition-all ${
                          activeTrackingId 
                          ? 'bg-gray-50 text-gray-300 border-gray-100 cursor-not-allowed' 
                          : 'bg-white border-embu-green text-embu-green hover:bg-embu-green hover:text-white'
                        }`}
                      >
                        Start Errand
                      </button>
                    )}
                  </li>
                ))}
              </ul>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

