export type CampusZone = 'Academic' | 'Hostels' | 'Admin' | 'Gate' | 'Mess' | 'Unknown';

export interface Coords {
  lat: number;
  lng: number;
}

export interface Errand {
  id: string;
  studentName: string;
  requestText: string;
  item: string;
  source: string;
  location: string;
  zone: CampusZone;
  price: number;
  status: 'Pending' | 'Active' | 'Completed';
  timestamp: number;
  isInternal: boolean;
  notes?: string;
  runnerCoords?: Coords;
  destinationCoords?: Coords;
  eta?: string;
}

export interface AIResponse {
  item: string;
  source: string;
  location: string;
  zone: CampusZone;
  isInternal: boolean;
  isCrossCampus: boolean;
  notes?: string;
  approxDestinationCoords?: Coords;
}

import React, { useState } from 'react';
import { parseErrandRequest } from '../services/geminiService';
import { Errand } from '../types';

interface OrderFormProps {
  onOrderPlaced: (errand: Errand) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ onOrderPlaced }) => {
  const [request, setRequest] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!request.trim()) return;

    setIsLoading(true);
    setError('');

    try {
      const result = await parseErrandRequest(request);

      const baseFee = 30;
      const distanceFee = result.isCrossCampus ? 10 : 0;

      const newErrand: Errand = {
        id: Math.random().toString(36).substr(2, 9),
        studentName: "Student User", 
        requestText: request,
        item: result.item,
        source: result.source,
        location: result.location,
        zone: result.zone,
        price: baseFee + distanceFee,
        status: 'Pending',
        timestamp: Date.now(),
        isInternal: result.isInternal,
        notes: result.notes,
        destinationCoords: result.approxDestinationCoords
      };

      onOrderPlaced(newErrand);
      setRequest('');
      alert(`Order placed! Total: KES ${newErrand.price}. Location: ${newErrand.location}. ${newErrand.notes || ''}`);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section className="p-4 bg-white rounded-xl shadow-md border border-gray-100 max-w-2xl mx-auto mt-6">
      <h2 className="text-xl font-bold text-embu-green mb-4">New Errand</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            What do you need?
          </label>
          <textarea
            value={request}
            onChange={(e) => setRequest(e.target.value)}
