import React, { useState, useMemo } from 'react';
import { Coords } from '../types';

interface TrackingMapProps {
  runnerCoords: Coords;
  destCoords?: Coords;
  destinationName?: string;
}

const TrackingMap: React.FC<TrackingMapProps> = ({ runnerCoords, destCoords, destinationName }) => {
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);

  // Simple Haversine-like distance calculation for campus scale
  const distance = useMemo(() => {
    if (!destCoords) return null;
    const lat1 = runnerCoords.lat;
    const lon1 = runnerCoords.lng;
    const lat2 = destCoords.lat;
    const lon2 = destCoords.lng;

    // Approximation for small distances
    const R = 6371e3; // metres
    const φ1 = lat1 * Math.PI/180;
    const φ2 = lat2 * Math.PI/180;
    const Δφ = (lat2-lat1) * Math.PI/180;
    const Δλ = (lon2-lon1) * Math.PI/180;

    const a = Math.sin(Δφ/2) * Math.sin(Δφ/2) +
              Math.cos(φ1) * Math.cos(φ2) *
              Math.sin(Δλ/2) * Math.sin(Δλ/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));

    const d = R * c; // in metres
    return Math.round(d);
  }, [runnerCoords, destCoords]);

  const mapUrl = `https://www.openstreetmap.org/export/embed.html?bbox=${runnerCoords.lng - 0.003}%2C${runnerCoords.lat - 0.003}%2C${runnerCoords.lng + 0.003}%2C${runnerCoords.lat + 0.003}&layer=mapnik&marker=${runnerCoords.lat}%2C${runnerCoords.lng}`;

  return (
    <div className="relative group">
      {/* Map Container */}
      <div 
        onClick={() => setIsDetailsOpen(!isDetailsOpen)}
        className="relative w-full h-64 bg-gray-200 rounded-2xl overflow-hidden border-2 border-embu-gold/30 shadow-inner cursor-pointer"
      >
        <iframe
          width="100%"
          height="100%"
          frameBorder="0"
          scrolling="no"
          marginHeight={0}
          marginWidth={0}
          src={mapUrl}
          title="Runner Location Map"
          className="pointer-events-none" // Disable internal iframe interaction to capture click on container
        ></iframe>

        {/* Interaction Layer Overlay */}
        <div className="absolute inset-0 bg-embu-green/5 group-hover:bg-transparent transition-colors pointer-events-none" />

        {/* Floating Controls */}
        <div className="absolute top-3 right-3 flex flex-col gap-2">
           <div className="bg-white/95 backdrop-blur px-3 py-1 rounded-full shadow-lg border border-embu-gold/50 text-[10px] font-black text-embu-green flex items-center gap-1.5 animate-pulse">
             <div className="w-1.5 h-1.5 rounded-full bg-red-500" /> LIVE
           </div>
           <button 
             className="w-8 h-8 bg-white/95 rounded-full shadow-lg border border-gray-100 flex items-center justify-center text-embu-green hover:scale-110 transition-transform"
             onClick={(e) => {
               e.stopPropagation();
               setIsDetailsOpen(!isDetailsOpen);
             }}
           >
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
             </svg>
           </button>
        </div>

        {/* Bottom Quick Info */}
        {!isDetailsOpen && (
           <div className="absolute bottom-3 left-3 right-3 bg-white/90 backdrop-blur p-3 rounded-xl border border-gray-100 shadow-xl flex justify-between items-center transform translate-y-0 group-hover:-translate-y-1 transition-transform">
             <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-embu-green" />
                <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Tracking Runner</span>
             </div>
             <div className="text-[10px] font-bold text-embu-green bg-embu-gold/20 px-2 py-0.5 rounded">
                Tap for detailed path
             </div>
           </div>
        )}
      </div>

      {/* Interactive Detail Drawer */}
      {isDetailsOpen && (
        <div className="mt-3 bg-white rounded-2xl border-2 border-embu-gold p-4 shadow-xl animate-in slide-in-from-bottom-4 duration-300">
          <div className="flex justify-between items-start mb-4">
            <h4 className="font-black text-embu-green uppercase tracking-tight">Mission Control</h4>
            <button onClick={() => setIsDetailsOpen(false)} className="text-gray-400 hover:text-red-500">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Distance Left</div>
              <div className="text-xl font-black text-embu-green flex items-baseline gap-1">
                {distance !== null ? distance : '--'} <span className="text-xs">meters</span>
              </div>
            </div>
            <div className="space-y-1">
              <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Heading To</div>
              <div className="text-sm font-bold truncate text-gray-700">{destinationName || 'Destination'}</div>
            </div>
          </div>

          <div className="mt-4 pt-4 border-t border-gray-100 flex flex-col gap-3">
             <div className="flex items-center justify-between text-[10px]">
                <span className="text-gray-400 font-bold uppercase">Runner Lat/Lng</span>
                <span className="font-mono text-gray-600 bg-gray-50 px-2 py-0.5 rounded">
                  {runnerCoords.lat.toFixed(4)}, {runnerCoords.lng.toFixed(4)}
                </span>
             </div>
             <div className="h-1.5 bg-gray-100 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-embu-gold transition-all duration-1000" 
                  style={{ width: distance !== null ? `${Math.max(0, 100 - (distance / 500) * 100)}%` : '0%' }}
                />
             </div>
             <p className="text-[9px] text-center text-gray-400 font-medium italic">
               Estimated walking speed on Embu Campus: 1.4m/s
             </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default TrackingMap;

import React, { useState, useEffect, useCallback } from 'react';
import { Errand, Coords } from './types';
import Header from './components/Header';
import OrderForm from './components/OrderForm';
import RunnerDashboard from './components/RunnerDashboard';
import TrackingMap from './components/TrackingMap';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [user, setUser] = useState<string | null>(null);
  const [view, setView] = useState<'student' | 'runner'>('student');
  const [errands, setErrands] = useState<Errand[]>([]);
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    const savedErrands = localStorage.getItem('embu-errands');
    const savedUser = localStorage.getItem('embu-user');

    if (savedErrands) setErrands(JSON.parse(savedErrands));
    if (savedUser) setUser(savedUser);

    setIsReady(true);
  }, []);

  useEffect(() => {
    if (isReady) {
      localStorage.setItem('embu-errands', JSON.stringify(errands));
    }
  }, [errands, isReady]);

  const handleLogin = (email: string) => {
    setUser(email);
    localStorage.setItem('embu-user', email);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('embu-user');
  };

  const handleOrderPlaced = (newErrand: Errand) => {
    // Attach current user's email to the errand
    const errandWithUser = { ...newErrand, studentName: user || 'Anonymous' };
    setErrands(prev => [errandWithUser, ...prev]);
  };

  const handleCompleteErrand = (id: string) => {
    setErrands(prev => prev.map(e => 
      e.id === id ? { ...e, status: 'Completed', runnerCoords: undefined, eta: undefined } : e
    ));
  };

  const handleStartErrand = (id: string) => {
    setErrands(prev => prev.map(e => 
      e.id === id ? { ...e, status: 'Active' } : e
    ));
  };

  const handleUpdateLocation = useCallback((id: string, coords: Coords, eta: string) => {
    setErrands(prev => prev.map(e => 
      e.id === id ? { ...e, runnerCoords: coords, eta } : e
    ));
  }, []);

  if (!isReady) return null;

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeErrandForStudent = errands.find(e => e.status === 'Active' || (e.status === 'Pending' && e.runnerCoords));

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <Header 
        view={view} 
        setView={setView} 
        userEmail={user} 
        onLogout={handleLogout} 
      />

      <main className="container mx-auto max-w-4xl pt-4">
        {view === 'student' ? (
          <div className="space-y-8">
            <div className="text-center px-4 mt-6">
              <h2 className="text-3xl font-black text-embu-green leading-tight">
                Embu <span className="text-embu-gold">CampusRunner</span>
              </h2>
              <p className="text-gray-600 mt-2 max-w-md mx-auto text-sm">
                Signed in as <span className="font-bold text-embu-green">{user}</span>. 
                Your personal assistant across the University of Embu.
              </p>
            </div>

            {activeErrandForStudent && (
              <section className="px-4 animate-in fade-in slide-in-from-top duration-500">
                <div className="bg-embu-green text-white rounded-3xl p-6 shadow-2xl border-4 border-embu-gold overflow-hidden relative">
                  <div className="relative z-10">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <span className="bg-embu-gold text-embu-green px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest">
                          Active Tracking
                        </span>
                        <h3 className="text-xl font-bold mt-1">Your {activeErrandForStudent.item} is on the way!</h3>
                      </div>
                      <div className="text-right">
                        <div className="text-xs opacity-80 uppercase font-bold">Arrival In</div>
                        <div className="text-2xl font-black text-embu-gold">{activeErrandForStudent.eta || 'Calculating...'}</div>
                      </div>
                    </div>

                    {activeErrandForStudent.runnerCoords ? (
                      <TrackingMap 
                        runnerCoords={activeErrandForStudent.runnerCoords} 
                        destCoords={activeErrandForStudent.destinationCoords}
                        destinationName={activeErrandForStudent.location}
                      />
                    ) : (
                      <div className="h-64 bg-white/10 rounded-2xl flex items-center justify-center border-2 border-dashed border-white/20">
                        <div className="text-center">
                          <svg className="w-10 h-10 text-embu-gold mx-auto mb-3 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                          </svg>
                          <p className="text-sm italic opacity-70">Awaiting Runner GPS Signal...</p>
                        </div>
                      </div>
                    )}

                    <div className="mt-4 flex items-center gap-3 text-sm">
                      <div className="w-10 h-10 bg-embu-gold rounded-full flex items-center justify-center text-embu-green shadow-inner">
                        <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg>
                      </div>
                      <div>
                        <p className="font-bold">Mission Status: In Progress</p>
