import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Coords } from '../types';

// Access Leaflet from the window object since it's loaded via CDN
declare const L: any;

interface TrackingMapProps {
  runnerCoords: Coords;
  destCoords?: Coords;
  destinationName?: string;
}

const TrackingMap: React.FC<TrackingMapProps> = ({ runnerCoords, destCoords, destinationName }) => {
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);
  const [routeDuration, setRouteDuration] = useState<number | null>(null); // Duration in seconds
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const routeLayerRef = useRef<any>(null);
  const runnerMarkerRef = useRef<any>(null);
  const destMarkerRef = useRef<any>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current) return;

    mapRef.current = L.map(mapContainerRef.current, {
      zoomControl: false,
      attributionControl: false
    }).setView([runnerCoords.lat, runnerCoords.lng], 17);

    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRef.current);

    // Initial markers
    runnerMarkerRef.current = L.circleMarker([runnerCoords.lat, runnerCoords.lng], {
      radius: 8,
      fillColor: "#006400",
      color: "#FFD700",
      weight: 3,
      opacity: 1,
      fillOpacity: 1
    }).addTo(mapRef.current);

    if (destCoords) {
      destMarkerRef.current = L.marker([destCoords.lat, destCoords.lng], {
        icon: L.divIcon({
          className: 'custom-div-icon',
          html: `<div style="background-color: #FFD700; width: 12px; height: 12px; border-radius: 50%; border: 2px solid #006400;"></div>`,
          iconSize: [12, 12],
          iconAnchor: [6, 6]
        })
      }).addTo(mapRef.current);
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Update Route and Markers
  useEffect(() => {
    if (!mapRef.current) return;

    // Update runner position
    runnerMarkerRef.current.setLatLng([runnerCoords.lat, runnerCoords.lng]);

    // Update destination marker if it changed
    if (destCoords) {
      if (destMarkerRef.current) {
        destMarkerRef.current.setLatLng([destCoords.lat, destCoords.lng]);
      } else {
        destMarkerRef.current = L.marker([destCoords.lat, destCoords.lng]).addTo(mapRef.current);
      }
    }

    // Fetch and Draw Routing Path
    const fetchRoute = async () => {
      if (!destCoords) return;

      try {
        // Use OSRM public routing API (foot profile for campus)
        const url = `https://router.project-osrm.org/route/v1/foot/${runnerCoords.lng},${runnerCoords.lat};${destCoords.lng},${destCoords.lat}?overview=full&geometries=geojson`;
        const response = await fetch(url);
        const data = await response.json();

        if (data.routes && data.routes.length > 0) {
          const routeGeoJSON = data.routes[0].geometry;
          const duration = data.routes[0].duration; // This is the estimated time in seconds

          setRouteDuration(duration);

          if (routeLayerRef.current) {
            routeLayerRef.current.remove();
          }

          routeLayerRef.current = L.geoJSON(routeGeoJSON, {
            style: {
              color: '#006400',
              weight: 5,
              opacity: 0.6,
              dashArray: '10, 10',
              lineJoin: 'round'
            }
          }).addTo(mapRef.current);

          // Gently pan to runner
          mapRef.current.panTo(runnerCoords);
        }
      } catch (err) {
        console.error("Routing error:", err);
      }
    };

    fetchRoute();
  }, [runnerCoords.lat, runnerCoords.lng, destCoords]);

  // Simple distance calculation for text details
  const distance = useMemo(() => {
    if (!destCoords) return null;
    const lat1 = runnerCoords.lat;
    const lon1 = runnerCoords.lng;
    const lat2 = destCoords.lat;
    const lon2 = destCoords.lng;
    const R = 6371e3; // metres
    const φ1 = lat1 * Math.PI/180;
    const φ2 = lat2 * Math.PI/180;
    const Δφ = (lat2-lat1) * Math.PI/180;
    const Δλ = (lon2-lon1) * Math.PI/180;
    const a = Math.sin(Δφ/2) * Math.sin(Δφ/2) + Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ/2) * Math.sin(Δλ/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return Math.round(R * c);
  }, [runnerCoords, destCoords]);

  // Format ETA text
  const etaText = useMemo(() => {
    if (routeDuration === null) return 'Calculating...';
    if (routeDuration < 60) return 'Under 1 min';
    const mins = Math.floor(routeDuration / 60);
    const secs = Math.round(routeDuration % 60);
    return secs > 0 ? `${mins}m ${secs}s` : `${mins} mins`;
  }, [routeDuration]);

  return (
    <div className="relative group">
      {/* Map Container */}
      <div 
        className="relative w-full h-72 bg-gray-200 rounded-3xl overflow-hidden border-2 border-embu-gold shadow-2xl transition-all hover:border-white"
      >
        <div 
          ref={mapContainerRef} 
          className="w-full h-full"
          onClick={() => setIsDetailsOpen(!isDetailsOpen)}
        />

        {/* Floating Controls */}
        <div className="absolute top-4 right-4 flex flex-col gap-2 z-[1000]">
           <div className="bg-white/95 backdrop-blur px-3 py-1.5 rounded-full shadow-lg border border-embu-gold/50 text-[10px] font-black text-embu-green flex items-center gap-1.5 animate-pulse">
             <div className="w-1.5 h-1.5 rounded-full bg-red-500" /> LIVE GPS
           </div>
           <button 
             className="w-10 h-10 bg-white/95 rounded-full shadow-lg border border-gray-100 flex items-center justify-center text-embu-green hover:scale-110 active:scale-95 transition-all"
             onClick={() => {
                if (mapRef.current) mapRef.current.setView([runnerCoords.lat, runnerCoords.lng], 18);
             }}
           >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
             </svg>
           </button>
        </div>

        {/* Legend */}
        <div className="absolute top-4 left-4 z-[1000] flex flex-col gap-1.5">
           <div className="bg-embu-green/90 backdrop-blur px-2.5 py-1 rounded-lg text-[9px] font-bold text-white flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-embu-gold border border-white" /> Runner Position
           </div>
           <div className="bg-white/90 backdrop-blur px-2.5 py-1 rounded-lg text-[9px] font-bold text-embu-green flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-embu-gold border border-embu-green" /> {destinationName || 'Destination'}
           </div>
        </div>

        {/* Interactive Bottom Bar */}
        <div 
          onClick={() => setIsDetailsOpen(!isDetailsOpen)}
          className="absolute bottom-4 left-4 right-4 bg-white/95 backdrop-blur p-4 rounded-2xl border border-gray-100 shadow-2xl flex justify-between items-center z-[1000] cursor-pointer hover:bg-white transition-colors group"
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-embu-green flex items-center justify-center text-embu-gold font-black shadow-inner">
              {routeDuration !== null ? Math.ceil(routeDuration / 60) : '?'}
            </div>
            <div>
              <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Estimated Arrival</div>
              <div className="text-sm font-black text-embu-green">
                {etaText}
              </div>
            </div>
          </div>
          <svg className={`w-5 h-5 text-embu-gold transition-transform duration-300 ${isDetailsOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 15l7-7 7 7" />
          </svg>
        </div>
      </div>

      {/* Expanded Details Drawer */}
      {isDetailsOpen && (
        <div className="mt-4 bg-white rounded-3xl border-2 border-embu-gold p-6 shadow-2xl animate-in slide-in-from-bottom-4 duration-500 overflow-hidden relative">
          <div className="absolute top-0 right-0 w-32 h-32 bg-embu-gold/5 rounded-full -mr-16 -mt-16 pointer-events-none" />

          <div className="relative z-10">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h4 className="font-black text-embu-green text-lg uppercase tracking-tight">Runner Progress</h4>
                <p className="text-xs text-gray-400 font-medium">Navigating University of Embu</p>
              </div>
              <div className="bg-embu-gold/10 text-embu-green px-3 py-1 rounded-full text-[10px] font-black uppercase">
                Active Route
              </div>
            </div>

            <div className="grid grid-cols-2 gap-6 mb-8">
              <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
                <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Remaining</div>
                <div className="text-2xl font-black text-embu-green flex items-baseline gap-1">
                  {distance !== null ? distance : '--'} <span className="text-xs">m</span>
                </div>
              </div>
              <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
                <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Arrival Time</div>
                <div className="text-sm font-bold text-gray-700 leading-tight">
                  {etaText}
                </div>
              </div>
            </div>

            <div className="space-y-4">
               <div className="flex items-center justify-between">
                  <span className="text-[10px] font-black text-gray-400 uppercase">Route Coverage</span>
                  <span className="text-[10px] font-bold text-embu-green">
                    {distance !== null ? Math.max(0, 100 - Math.round((distance/500)*100)) : 0}% Progress
                  </span>
               </div>
               <div className="h-2.5 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                  <div 
                    className="h-full bg-embu-green transition-all duration-1000 shadow-[0_0_10px_rgba(0,100,0,0.3)]" 
                    style={{ width: distance !== null ? `${Math.max(5, 100 - (distance / 500) * 100)}%` : '5%' }}
                  />
               </div>
               <div className="flex justify-between text-[9px] font-bold text-gray-400 px-1">
                  <span>DISPATCH</span>
                  <span>ARRIVED</span>
               </div>
            </div>

            <div className="mt-8 pt-6 border-t border-gray-100 flex items-center gap-4">
              <div className="w-12 h-12 bg-embu-gold/20 rounded-2xl flex items-center justify-center text-embu-green">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 18h.01M8 21h8a2 2 0 002-2V5a2 2 0 00-2-2H8a2 2 0 00-2 2v14a2 2 0 002 2z" />
                </svg>
              </div>
              <div>
                <p className="text-xs font-black text-embu-green uppercase tracking-wide">Live Telemetry</p>
