{
  "name": "ERRANDS SERVICE",
  "description": "An intelligent errand dispatcher for University of Embu students and runners, using AI to optimize campus logistics.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are the logistics coordinator for 'ERRANDS SERVICE.' You know the University of Embu layout perfectly.
Main Landmarks: 
- The Gate (-0.5050, 37.4580)
- New Library (-0.5065, 37.4595)
- Graduation Square (-0.5070, 37.4590)
- School of Agriculture (-0.5080, 37.4610)
- Hostel Ngiri (-0.5100, 37.4620)
- Hostel Simba (-0.5110, 37.4625)
- The Mess (-0.5075, 37.4600)
- Science Labs (-0.5060, 37.4590)
- School of Nursing (-0.5085, 37.4615)
- Old Admin Block (-0.5055, 37.4585)

Your Task: When a student sends a request, identify the item, source (pick-up point), location (drop-off point), and approximate coordinates for that location.

Mapping Rules:
1. If they are in the New Library, remind them that deliveries must be met at the entrance.
2. If they are in Hostels, ask for the room number if not provided.
3. Determine if the trip is "Internal" and "Cross-Campus".
4. Provide approximate lat/lng coordinates based on the landmarks above.

Output MUST be a structured JSON response.`;

export const parseErrandRequest = async (userInput: string): Promise<AIResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: userInput,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          source: { type: Type.STRING },
          location: { type: Type.STRING },
          zone: { 
            type: Type.STRING, 
            enum: ['Academic', 'Hostels', 'Admin', 'Gate', 'Mess', 'Unknown']
          },
          isInternal: { type: Type.BOOLEAN },
          isCrossCampus: { type: Type.BOOLEAN },
          notes: { type: Type.STRING },
          approxDestinationCoords: {
            type: Type.OBJECT,
            properties: {
              lat: { type: Type.NUMBER },
              lng: { type: Type.NUMBER }
            },
            required: ["lat", "lng"]
          }
        },
        required: ["item", "source", "location", "zone", "isInternal", "isCrossCampus", "approxDestinationCoords"]
      }
    }
  });

  try {
    const text = response.text;
    return JSON.parse(text) as AIResponse;
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    throw new Error("Could not understand the errand request. Please be more specific about the Embu Uni location.");
  }
};

