import React, { useMemo, useEffect, useState } from 'react';
import { Errand, Coords } from '../types';

interface RunnerDashboardProps {
  errands: Errand[];
  onComplete: (id: string) => void;
  onUpdateLocation: (id: string, coords: Coords, eta: string) => void;
  onStartErrand: (id: string) => void;
}

const RunnerDashboard: React.FC<RunnerDashboardProps> = ({ errands, onComplete, onUpdateLocation, onStartErrand }) => {
  const [activeTrackingId, setActiveTrackingId] = useState<string | null>(null);
  const [currentSpeed, setCurrentSpeed] = useState<number | null>(null);

  const pendingErrands = useMemo(() => 
    errands.filter(e => e.status !== 'Completed'), 
    [errands]
  );

  useEffect(() => {
    let watchId: number;

    if (activeTrackingId) {
      if ('geolocation' in navigator) {
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            const coords = {
              lat: position.coords.latitude,
              lng: position.coords.longitude
            };

            // Capture speed if provided by hardware
            if (position.coords.speed !== null) {
              setCurrentSpeed(position.coords.speed);
            }

            // ETA will be refined on the receiver side (TrackingMap) using routing,
            // but we send a simple placeholder for general status.
            onUpdateLocation(activeTrackingId, coords, 'Active');
          },
          (error) => console.error("GPS Error:", error),
          { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
        );
      }
    }

    return () => {
      if (watchId) navigator.geolocation.clearWatch(watchId);
    };
  }, [activeTrackingId, onUpdateLocation]);

  const groupedErrands = useMemo(() => {
    const groups: Record<string, Errand[]> = {};
    pendingErrands.forEach(errand => {
      if (!groups[errand.location]) {
        groups[errand.location] = [];
      }
      groups[errand.location].push(errand);
    });
    return groups;
  }, [pendingErrands]);

  const handleStart = (id: string) => {
    setActiveTrackingId(id);
    onStartErrand(id);
  };

  const handleFinish = (id: string) => {
    if (activeTrackingId === id) {
      setActiveTrackingId(null);
      setCurrentSpeed(null);
    }
    onComplete(id);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-embu-green p-6 rounded-2xl text-white shadow-xl flex justify-between items-center relative overflow-hidden">
        <div className="absolute -bottom-4 -left-4 w-24 h-24 bg-white opacity-5 rounded-full" />
        <div className="relative z-10">
          <h2 className="text-2xl font-bold">Runner Dashboard</h2>
          <p className="text-embu-gold font-medium">Campus Logistics Console</p>
        </div>
        <div className="bg-white/10 p-3 rounded-xl border border-white/20 relative z-10">
          <div className="text-[10px] uppercase opacity-70 tracking-widest font-bold">Runner Status</div>
