import React, { useMemo, useEffect, useState } from 'react';
import { Errand, Coords } from '../types';

interface RunnerDashboardProps {
  errands: Errand[];
  onComplete: (id: string) => void;
  onUpdateLocation: (id: string, coords: Coords, eta: string) => void;
  onStartErrand: (id: string) => void;
}

const RunnerDashboard: React.FC<RunnerDashboardProps> = ({ errands, onComplete, onUpdateLocation, onStartErrand }) => {
  const [activeTrackingId, setActiveTrackingId] = useState<string | null>(null);
  const [currentSpeed, setCurrentSpeed] = useState<number | null>(null);
  const [gpsError, setGpsError] = useState<string | null>(null);

  const pendingErrands = useMemo(() => 
    errands.filter(e => e.status !== 'Completed'), 
    [errands]
  );

  useEffect(() => {
    let watchId: number;

    if (activeTrackingId) {
      if ('geolocation' in navigator) {
        setGpsError(null);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            const coords = {
              lat: position.coords.latitude,
              lng: position.coords.longitude
            };

            setGpsError(null);
            if (position.coords.speed !== null) {
              setCurrentSpeed(position.coords.speed);
            }
            onUpdateLocation(activeTrackingId, coords, 'Active');
          },
          (error) => {
            console.error("GPS Error:", error);
            if (error.code === error.PERMISSION_DENIED) {
              setGpsError("Location access denied. Please go to your browser settings, click the lock icon in the address bar, and allow 'Location' for this site.");
            } else if (error.code === error.POSITION_UNAVAILABLE) {
              setGpsError("GPS position unavailable. Ensure you have a clear sky view and your device's location is turned on.");
            } else if (error.code === error.TIMEOUT) {
              setGpsError("GPS request timed out. Checking signal...");
            } else {
              setGpsError("An unknown GPS error occurred.");
            }
          },
          { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
        );
      } else {
        setGpsError("Your browser does not support geolocation tracking.");
      }
    }

    return () => {
      if (watchId) navigator.geolocation.clearWatch(watchId);
    };
  }, [activeTrackingId, onUpdateLocation]);

  const groupedErrands = useMemo(() => {
    const groups: Record<string, Errand[]> = {};
    pendingErrands.forEach(errand => {
      if (!groups[errand.location]) {
        groups[errand.location] = [];
      }
      groups[errand.location].push(errand);
    });
    return groups;
  }, [pendingErrands]);

  const handleStart = (id: string) => {
    setActiveTrackingId(id);
    onStartErrand(id);
  };

  const handleFinish = (id: string) => {
    if (activeTrackingId === id) {
      setActiveTrackingId(null);
      setCurrentSpeed(null);
      setGpsError(null);
    }
    onComplete(id);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-embu-green p-6 rounded-2xl text-white shadow-xl flex justify-between items-center relative overflow-hidden">
        <div className="absolute -bottom-4 -left-4 w-24 h-24 bg-white opacity-5 rounded-full" />
        <div className="relative z-10">
          <h2 className="text-2xl font-bold">Runner Dashboard</h2>
          <p className="text-embu-gold font-medium">Campus Logistics Console</p>
        </div>
        <div className="bg-white/10 p-3 rounded-xl border border-white/20 relative z-10">
          <div className="text-[10px] uppercase opacity-70 tracking-widest font-bold">Runner Status</div>
          <div className="flex items-center gap-2 text-sm font-bold">
            <div className={`w-2.5 h-2.5 rounded-full ${activeTrackingId ? (gpsError ? 'bg-red-500' : 'bg-green-400 animate-pulse') : 'bg-embu-gold'}`} />
            {gpsError ? 'GPS Locked' : activeTrackingId ? 'Tracking Active' : 'Waiting for Tasks'}
          </div>
        </div>
      </div>

      {gpsError && (
        <div className="bg-red-50 border-2 border-red-100 p-6 rounded-[2rem] animate-in fade-in slide-in-from-top-4">
          <div className="flex gap-4">
            <div className="w-12 h-12 bg-red-100 rounded-2xl flex items-center justify-center text-red-600 shrink-0">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <div>
              <h4 className="font-black text-red-800 uppercase text-xs tracking-wider mb-1">GPS Action Required</h4>
              <p className="text-sm text-red-600 font-medium leading-relaxed">{gpsError}</p>
              <p className="text-[10px] text-red-400 mt-2 font-bold uppercase">To fix: Tap the lock icon in the address bar &rarr; Permissions &rarr; Reset/Allow Location</p>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {Object.entries(groupedErrands).length === 0 ? (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border-2 border-dashed border-gray-100 text-gray-400">
             <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
             </div>
             <p className="font-bold uppercase tracking-widest text-[10px]">No active errands. Enjoy the break!</p>
          </div>
        ) : (
          Object.entries(groupedErrands).map(([location, group]) => (
            <div key={location} className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full hover:shadow-xl transition-shadow duration-300">
              <div className="bg-gray-50/50 px-6 py-4 border-b flex justify-between items-center">
                <div>
                   <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Destination</div>
                   <h3 className="font-bold text-embu-green truncate max-w-[150px]">{location}</h3>
                </div>
                <span className="bg-embu-gold text-embu-green px-3 py-1 rounded-full text-[10px] font-black shadow-sm">
                  {group.length} TASK{group.length > 1 ? 'S' : ''}
                </span>
              </div>
              <ul className="divide-y flex-grow">
                {group.map(errand => (
                  <li key={errand.id} className={`p-6 transition-all ${activeTrackingId === errand.id ? 'bg-embu-green/5 ring-4 ring-embu-green/10 ring-inset' : ''}`}>
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex flex-col">
                        <div className="font-black text-gray-800 text-lg leading-tight">{errand.item}</div>
                        <div className="text-[10px] font-black text-embu-green uppercase tracking-widest">Requested by: {errand.studentName}</div>
                      </div>
                      <div className="text-embu-green font-black">KES {errand.price}</div>
                    </div>
                    <div className="flex items-center gap-2 text-xs text-gray-500 mb-6 font-medium">
                       <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                       </svg>
                       Pick-up: {errand.source}
                    </div>

                    {errand.status === 'Active' ? (
                      <div className="space-y-4">
                        <div className="bg-white border-2 border-embu-green/20 rounded-2xl p-3 flex items-center justify-between">
                          <div className="flex flex-col">
                            <span className="text-[9px] font-black text-gray-400 uppercase tracking-tighter">GPS Speed</span>
                            <span className="font-black text-embu-green">
                              {currentSpeed !== null ? `${(currentSpeed * 3.6).toFixed(1)} km/h` : (gpsError ? '--' : 'Calculating...')}
                            </span>
                          </div>
                          <div className="h-8 w-px bg-gray-100" />
                          <div className="flex flex-col text-right">
                            <span className="text-[9px] font-black text-gray-400 uppercase tracking-tighter">Signal</span>
                            <span className={`font-black flex items-center gap-1 justify-end ${gpsError ? 'text-red-500' : 'text-green-500'}`}>
                              {gpsError ? 'Error' : 'Stable'} <div className={`w-1.5 h-1.5 rounded-full ${gpsError ? 'bg-red-500' : 'bg-green-500 animate-ping'}`} />
                            </span>
                          </div>
                        </div>
                        <button
                          onClick={() => handleFinish(errand.id)}
                          className="w-full py-4 bg-embu-green text-white rounded-2xl font-black text-sm shadow-lg shadow-embu-green/20 hover:bg-embu-darkGreen hover:scale-[1.02] active:scale-[0.98] transition-all"
                        >
                          Mark as Delivered
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => handleStart(errand.id)}
                        disabled={!!activeTrackingId}
                        className={`w-full py-4 rounded-2xl font-black text-sm border-4 transition-all ${
                          activeTrackingId 
                          ? 'bg-gray-50 text-gray-300 border-gray-100 cursor-not-allowed' 
                          : 'bg-white border-embu-green text-embu-green hover:bg-embu-green hover:text-white active:scale-[0.98]'
                        }`}
                      >
                        Start Delivery
                      </button>
                    )}
                  </li>
                ))}
              </ul>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

