import { GoogleGenAI } from "@google/genai";
import { AIResponse, Coords, GroundingLink } from "../types";

const SYSTEM_INSTRUCTION = `You are the logistics coordinator for 'ERRANDS SERVICE.' You know the University of Embu layout perfectly.
Main Landmarks: 
- The Gate (-0.5050, 37.4580)
- New Library (-0.5065, 37.4595)
- Graduation Square (-0.5070, 37.4590)
- School of Agriculture (-0.5080, 37.4610)
- Hostel Ngiri (-0.5100, 37.4620)
- Hostel Simba (-0.5110, 37.4625)
- The Mess (-0.5075, 37.4600)
- Science Labs (-0.5060, 37.4590)
- School of Nursing (-0.5085, 37.4615)
- Old Admin Block (-0.5055, 37.4585)

Your Task: When a student sends a request, identify the item, source (pick-up point), location (drop-off point), and approximate coordinates for that location. Use Google Maps to verify specific shop names or recent campus updates.

Mapping Rules:
1. If they are in the New Library, remind them that deliveries must be met at the entrance.
2. If they are in Hostels, ask for the room number if not provided.
3. Determine if the trip is "Internal" and "Cross-Campus".
4. Provide approximate lat/lng coordinates.

Return your answer as a raw JSON object string ONLY, without markdown formatting blocks, containing these fields:
item (string), source (string), location (string), zone (enum: Academic, Hostels, Admin, Gate, Mess, Unknown), isInternal (boolean), isCrossCampus (boolean), notes (string), approxDestinationCoords ({lat: number, lng: number}).`;

export const parseErrandRequest = async (userInput: string, userLocation?: Coords): Promise<AIResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: userInput,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleMaps: {} }],
      toolConfig: userLocation ? {
        retrievalConfig: {
          latLng: {
            latitude: userLocation.lat,
            longitude: userLocation.lng
          }
        }
      } : undefined
    }
  });

  try {
    const text = response.text || "";
    // Attempt to extract JSON if model wrapped it in markdown
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    const jsonStr = jsonMatch ? jsonMatch[0] : text;
    const parsed = JSON.parse(jsonStr) as AIResponse;

    // Extract grounding links
    const groundingLinks: GroundingLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.maps) {
          groundingLinks.push({
            title: chunk.maps.title || "View on Maps",
            uri: chunk.maps.uri
          });
        }
      });
    }

    return { ...parsed, groundingLinks };
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    throw new Error("Could not understand the errand request. Please be more specific about the Embu Uni location.");
  }
};

