import React, { useMemo, useEffect, useState, useRef } from 'react';
import { Errand, Coords, TransportMode } from '../types';

interface RunnerDashboardProps {
  errands: Errand[];
  onComplete: (id: string) => void;
  onUpdateLocation: (id: string, coords: Coords, speed: number | null, mode: TransportMode, eta: string) => void;
  onStartErrand: (id: string) => void;
}

const RunnerDashboard: React.FC<RunnerDashboardProps> = ({ errands, onComplete, onUpdateLocation, onStartErrand }) => {
  const [activeTrackingId, setActiveTrackingId] = useState<string | null>(null);
  const [currentSpeed, setCurrentSpeed] = useState<number | null>(null);
  const [transportMode, setTransportMode] = useState<TransportMode>('Walking');
  const [gpsError, setGpsError] = useState<string | null>(null);
  const [now, setNow] = useState(Date.now());

  // Use a ref to store latest transport mode to avoid stale closures in geolocation watcher
  const transportModeRef = useRef<TransportMode>('Walking');
  useEffect(() => {
    transportModeRef.current = transportMode;
  }, [transportMode]);

  useEffect(() => {
    const timer = setInterval(() => setNow(Date.now()), 60000);
    return () => clearInterval(timer);
  }, []);

  const pendingErrands = useMemo(() => 
    errands.filter(e => e.status !== 'Completed'), 
    [errands]
  );

  useEffect(() => {
    let watchId: number;

    if (activeTrackingId) {
      if ('geolocation' in navigator) {
        setGpsError(null);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            const coords = {
              lat: position.coords.latitude,
              lng: position.coords.longitude
            };

            setGpsError(null);
            const speed = position.coords.speed;
            if (speed !== null) {
              setCurrentSpeed(speed);
            }
            onUpdateLocation(activeTrackingId, coords, speed, transportModeRef.current, 'Active');
          },
          (error) => {
            console.error("GPS Error:", error);
            if (error.code === error.PERMISSION_DENIED) {
              setGpsError("Location access denied.");
            } else {
              setGpsError("GPS position unavailable.");
            }
          },
          { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
        );
      } else {
        setGpsError("Your browser does not support geolocation tracking.");
      }
    }

    return () => {
      if (watchId) navigator.geolocation.clearWatch(watchId);
    };
  }, [activeTrackingId, onUpdateLocation]);

  const groupedErrands = useMemo(() => {
    const groups: Record<string, Errand[]> = {};
    pendingErrands.forEach(errand => {
      if (!groups[errand.location]) {
        groups[errand.location] = [];
      }
      groups[errand.location].push(errand);
    });
    return groups;
  }, [pendingErrands]);

  const formatWaitTime = (timestamp: number) => {
    const diffInMins = Math.floor((now - timestamp) / 60000);
    return diffInMins < 1 ? '< 1m' : `${diffInMins}m`;
  };

  const handleStart = (id: string) => {
    setActiveTrackingId(id);
    onStartErrand(id);
  };

  const handleFinish = (id: string) => {
    if (activeTrackingId === id) {
      setActiveTrackingId(null);
      setCurrentSpeed(null);
      setGpsError(null);
    }
    onComplete(id);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-embu-green p-6 rounded-2xl text-white shadow-xl flex justify-between items-center relative overflow-hidden">
        <div className="absolute -bottom-4 -left-4 w-24 h-24 bg-white opacity-5 rounded-full" />
        <div className="relative z-10">
          <h2 className="text-2xl font-bold">Runner Dashboard</h2>
          <p className="text-embu-gold font-medium">Logistics Console</p>
        </div>
        <div className="bg-white/10 p-3 rounded-xl border border-white/20 relative z-10 text-right">
          <div className="text-[10px] uppercase opacity-70 tracking-widest font-bold">Runner Active</div>
          <div className="flex items-center gap-2 text-sm font-bold justify-end">
            <div className={`w-2 h-2 rounded-full ${activeTrackingId ? 'bg-green-400 animate-pulse' : 'bg-embu-gold'}`} />
            {activeTrackingId ? 'Tracking' : 'Waiting'}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {Object.entries(groupedErrands).length === 0 ? (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border-2 border-dashed border-gray-100 text-gray-400">
             <p className="font-bold uppercase tracking-widest text-[10px]">No active errands. Enjoy the break!</p>
          </div>
        ) : (
          Object.entries(groupedErrands).map(([location, group]) => (
            <div key={location} className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full hover:shadow-xl transition-shadow duration-300">
              <div className="bg-gray-50/50 px-6 py-4 border-b flex justify-between items-center">
                <h3 className="font-bold text-embu-green truncate max-w-[150px]">{location}</h3>
                <span className="bg-embu-gold text-embu-green px-3 py-1 rounded-full text-[10px] font-black shadow-sm">
                  {group.length} TASK{group.length > 1 ? 'S' : ''}
                </span>
              </div>
              <ul className="divide-y flex-grow">
                {group.map(errand => (
                  <li key={errand.id} className={`p-6 transition-all ${activeTrackingId === errand.id ? 'bg-embu-green/5' : ''}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex flex-col">
                        <div className="font-black text-gray-800 text-lg leading-tight">{errand.item}</div>
                        <div className="text-[10px] font-black text-embu-green uppercase tracking-widest mt-1">Requester: {errand.studentName}</div>
                      </div>
                      <div className="text-embu-green font-black">KES {errand.price}</div>
                    </div>

                    {errand.status === 'Active' ? (
                      <div className="space-y-4">
                        <div className="bg-white border-2 border-embu-green/10 rounded-2xl p-4">
                          <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest block mb-3">Transport Mode</label>
                          <div className="grid grid-cols-3 gap-2">
                            {(['Walking', 'Bike', 'PSV'] as TransportMode[]).map(mode => (
                              <button
                                key={mode}
                                onClick={() => setTransportMode(mode)}
                                className={`py-3 px-2 rounded-xl text-[10px] font-black uppercase flex flex-col items-center gap-1.5 transition-all border-2 ${
                                  transportMode === mode 
                                  ? 'bg-embu-green border-embu-green text-white shadow-lg shadow-embu-green/20' 
                                  : 'bg-gray-50 border-transparent text-gray-400 grayscale'
                                }`}
                              >
                                {mode === 'Walking' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7-7 7M5 5l7 7-7 7" strokeWidth="2.5"/></svg>}
                                {mode === 'Bike' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2.5"/></svg>}
                                {mode === 'PSV' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2" strokeWidth="2.5"/></svg>}
                                {mode}
                              </button>
                            ))}
                          </div>
                        </div>

                        <div className="flex gap-2">
                          <div className="flex-1 bg-white border border-gray-100 rounded-2xl p-3 text-center">
                            <div className="text-[9px] font-black text-gray-400 uppercase tracking-tighter mb-1">GPS Speed</div>
                            <div className="font-black text-embu-green text-sm">
                              {currentSpeed !== null ? `${(currentSpeed * 3.6).toFixed(1)} km/h` : '0.0 km/h'}
                            </div>
                          </div>
                          <button
                            onClick={() => handleFinish(errand.id)}
                            className="flex-[2] py-4 bg-embu-green text-white rounded-2xl font-black text-sm shadow-lg hover:bg-embu-darkGreen transition-all"
                          >
                            Mark Delivered
                          </button>
                        </div>
                      </div>
                    ) : (
                      <button
                        onClick={() => handleStart(errand.id)}
                        disabled={!!activeTrackingId}
                        className={`w-full py-4 rounded-2xl font-black text-sm border-2 transition-all ${
                          activeTrackingId 
                          ? 'bg-gray-50 text-gray-300 border-gray-100' 
                          : 'bg-white border-embu-green text-embu-green hover:bg-embu-green hover:text-white'
                        }`}
                      >
                        Start Delivery
                      </button>
                    )}
                  </li>
                ))}
              </ul>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default RunnerDashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Coords, TransportMode } from '../types';

// Access Leaflet from the window object since it's loaded via CDN
declare const L: any;

interface TrackingMapProps {
  runnerCoords: Coords;
  runnerSpeed?: number;
  transportMode?: TransportMode;
  destCoords?: Coords;
  destinationName?: string;
}

const TrackingMap: React.FC<TrackingMapProps> = ({ runnerCoords, runnerSpeed, transportMode = 'Walking', destCoords, destinationName }) => {
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);
  const [routeDuration, setRouteDuration] = useState<number | null>(null); // Duration in seconds from OSRM
  const [myCoords, setMyCoords] = useState<Coords | null>(null);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const routeLayerRef = useRef<any>(null);
  const runnerMarkerRef = useRef<any>(null);
  const destMarkerRef = useRef<any>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current) return;

    mapRef.current = L.map(mapContainerRef.current, {
      zoomControl: false,
      attributionControl: false
    }).setView([runnerCoords.lat, runnerCoords.lng], 17);

    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRef.current);

    runnerMarkerRef.current = L.circleMarker([runnerCoords.lat, runnerCoords.lng], {
      radius: 8,
      fillColor: "#006400",
      color: "#FFD700",
      weight: 3,
      opacity: 1,
      fillOpacity: 1
    }).addTo(mapRef.current);

    if (destCoords) {
      destMarkerRef.current = L.marker([destCoords.lat, destCoords.lng], {
        icon: L.divIcon({
          className: 'custom-div-icon',
          html: `<div style="background-color: #FFD700; width: 12px; height: 12px; border-radius: 50%; border: 2px solid #006400;"></div>`,
          iconSize: [12, 12],
          iconAnchor: [6, 6]
        })
      }).addTo(mapRef.current);
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Update Route and Markers
  useEffect(() => {
    if (!mapRef.current) return;

    runnerMarkerRef.current.setLatLng([runnerCoords.lat, runnerCoords.lng]);

    const fetchRoute = async () => {
      if (!destCoords) return;
      try {
        const url = `https://router.project-osrm.org/route/v1/foot/${runnerCoords.lng},${runnerCoords.lat};${destCoords.lng},${destCoords.lat}?overview=full&geometries=geojson`;
        const response = await fetch(url);
        const data = await response.json();

        if (data.routes && data.routes.length > 0) {
          setRouteDuration(data.routes[0].duration);
          if (routeLayerRef.current) routeLayerRef.current.remove();
          routeLayerRef.current = L.geoJSON(data.routes[0].geometry, {
            style: { color: '#006400', weight: 5, opacity: 0.6, dashArray: '10, 10' }
          }).addTo(mapRef.current);
        }
      } catch (err) {
        console.error("Routing error:", err);
      }
    };

    fetchRoute();
  }, [runnerCoords.lat, runnerCoords.lng, destCoords]);

  const etaText = useMemo(() => {
    if (routeDuration === null) return 'Calculating...';

    // OSRM base walking speed is roughly 1.4 m/s
    const baselineWalkingSpeed = 1.39;

    // Define baseline speeds for modes (m/s)
    const modeSpeedMap: Record<TransportMode, number> = {
      'Walking': 1.39,
      'Bike': 5.5, // ~20 km/h
      'PSV': 8.3   // ~30 km/h
    };

    const targetSpeed = modeSpeedMap[transportMode];
    let effectiveDuration = routeDuration * (baselineWalkingSpeed / targetSpeed);

    // If we have live GPS speed and it's significant, use a blend
    if (runnerSpeed && runnerSpeed > 0.5) {
      // 70% weighted toward current speed, 30% toward mode baseline
      const blendedSpeed = (runnerSpeed * 0.7) + (targetSpeed * 0.3);
      effectiveDuration = routeDuration * (baselineWalkingSpeed / blendedSpeed);
    }

    if (effectiveDuration < 30) return 'Arriving now';
    if (effectiveDuration < 60) return 'Under 1m';

    const mins = Math.floor(effectiveDuration / 60);
    return `${mins}m ${Math.round(effectiveDuration % 60)}s`;
  }, [routeDuration, runnerSpeed, transportMode]);

  return (
    <div className="relative group">
      <div className="relative w-full h-64 bg-gray-200 rounded-3xl overflow-hidden border-2 border-embu-gold shadow-2xl">
        <div ref={mapContainerRef} className="w-full h-full" onClick={() => setIsDetailsOpen(!isDetailsOpen)} />

        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-2">
           <div className="bg-white/95 backdrop-blur px-3 py-1.5 rounded-full shadow-lg border border-embu-gold/50 text-[10px] font-black text-embu-green flex items-center gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse" /> LIVE GPS
           </div>
        </div>

        <div 
          onClick={() => setIsDetailsOpen(!isDetailsOpen)}
          className="absolute bottom-4 left-4 right-4 bg-white/95 backdrop-blur p-4 rounded-2xl border border-gray-100 shadow-2xl flex justify-between items-center z-[1000] cursor-pointer"
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-embu-green flex items-center justify-center text-embu-gold font-black shadow-inner">
               {transportMode === 'Walking' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>}
               {transportMode === 'Bike' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>}
               {transportMode === 'PSV' && <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeWidth="2" d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2" /></svg>}
            </div>
            <div>
              <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Runner is {transportMode}</div>
              <div className="text-sm font-black text-embu-green">{etaText}</div>
            </div>
          </div>
          <svg className={`w-5 h-5 text-embu-gold transition-transform duration-300 ${isDetailsOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 15l7-7 7 7" />
          </svg>
        </div>
      </div>

      {isDetailsOpen && (
